columns.handlerTsCode:
(line) => {
    const t = line.json_content ?? {}, role = t.message?.role ?? t.type ?? "unknown";
    return {
      text: role,
      facets: [{ name: "role", value: role }]
    };
  }

(line) => {
    const content = (line.json_content ?? {}).message?.content;
    let text = "";
    if (typeof content === "string")
      text = content;
    else if (Array.isArray(content))
      text = content.map((b) => {
        if (b.type === "text" && typeof b.text === "string")
          return b.text;
        if (b.type === "tool_use")
          return `[tool_use: ${b.name ?? "?"}]`;
        if (b.type === "tool_result")
          return "[tool_result]";
        return "";
      }).filter(Boolean).join(`
`);
    return { text };
  }

middlewares.handlerTsCode:
(line) => {
    if (!line.is_json)
      return;
    const t = line.json_content;
    if (t.type !== "user" && t.type !== "assistant")
      return;
    if (t.timestamp) {
      const ms = Date.parse(t.timestamp);
      if (!Number.isNaN(ms))
        line.order_key = ms;
    }
    return line;
  }
